class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());
        this.update(initialInputs);
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight;
    }

    drawArc(x, y, radius, startAngle, endAngle, color, label) {
        this.ctx.beginPath();
        this.ctx.strokeStyle = color;
        this.ctx.lineWidth = 1.5;
        this.ctx.arc(x, y, radius, startAngle, endAngle);
        this.ctx.stroke();
        if (label) {
            const midAngle = (startAngle + endAngle) / 2;
            const lx = x + (radius + 15) * Math.cos(midAngle);
            const ly = y + (radius + 15) * Math.sin(midAngle);
            this.ctx.fillStyle = color;
            this.ctx.font = '12px Inter, sans-serif';
            this.ctx.textAlign = 'center';
            this.ctx.fillText(label, lx, ly);
        }
    }

    update(inputs) {
        const { canvas, ctx } = this;
        const w = canvas.width;
        const h = canvas.height;
        const n1 = parseFloat(inputs.n1);
        const n2 = parseFloat(inputs.n2);
        const thetaI = (parseFloat(inputs.angle) * Math.PI) / 180;

        ctx.clearRect(0, 0, w, h);

        const centerX = w / 2;
        const centerY = h / 2;
        const rayLength = Math.min(w, h) * 0.4;

        // Draw Backgrounds
        ctx.fillStyle = '#f8fafc'; // Air-like
        ctx.fillRect(0, 0, w, centerY);
        ctx.fillStyle = '#dbeafe'; // Water/Glass-like
        ctx.fillRect(0, centerY, w, h);

        // Interface line
        ctx.strokeStyle = '#475569';
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(0, centerY);
        ctx.lineTo(w, centerY);
        ctx.stroke();

        // Normal line
        ctx.setLineDash([8, 8]);
        ctx.strokeStyle = '#94a3b8';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(centerX, 20);
        ctx.lineTo(centerX, h - 20);
        ctx.stroke();
        ctx.setLineDash([]);

        // Physics Calculation
        const sinThetaR = (n1 / n2) * Math.sin(thetaI);
        const isTIR = sinThetaR > 1.0;
        let thetaR = isTIR ? null : Math.asin(sinThetaR);

        // Incident Ray
        const incidentX = centerX - rayLength * Math.sin(thetaI);
        const incidentY = centerY - rayLength * Math.cos(thetaI);
        ctx.strokeStyle = '#f59e0b';
        ctx.lineWidth = 4;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(incidentX, incidentY);
        ctx.lineTo(centerX, centerY);
        ctx.stroke();

        // Reflected Ray (always present, but brighter during TIR)
        const reflectX = centerX + rayLength * Math.sin(thetaI);
        const reflectY = centerY - rayLength * Math.cos(thetaI);
        ctx.strokeStyle = isTIR ? '#f59e0b' : 'rgba(245, 158, 11, 0.3)';
        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.lineTo(reflectX, reflectY);
        ctx.stroke();

        if (!isTIR) {
            // Refracted Ray
            const refractX = centerX + rayLength * Math.sin(thetaR);
            const refractY = centerY + rayLength * Math.cos(thetaR);
            ctx.strokeStyle = '#3b82f6';
            ctx.beginPath();
            ctx.moveTo(centerX, centerY);
            ctx.lineTo(refractX, refractY);
            ctx.stroke();

            // Refraction angle arc
            this.drawArc(centerX, centerY, 50, Math.PI / 2 - thetaR, Math.PI / 2, '#3b82f6', (thetaR * 180 / Math.PI).toFixed(1) + '°');
        } else {
            // Critical Angle Text
            const criticalAngle = Math.asin(n2 / n1) * 180 / Math.PI;
            ctx.fillStyle = '#ef4444';
            ctx.font = 'bold 16px Inter, sans-serif';
            ctx.textAlign = 'left';
            ctx.fillText('Total Internal Reflection!', 20, h - 40);
            ctx.font = '14px Inter, sans-serif';
            ctx.fillText('Critical Angle: ' + criticalAngle.toFixed(1) + '°', 20, h - 20);
        }

        // Incident angle arc
        this.drawArc(centerX, centerY, 60, -Math.PI / 2, -Math.PI / 2 + thetaI, '#f59e0b', inputs.angle + '°');

        // Labels
        ctx.fillStyle = '#334155';
        ctx.font = 'bold 14px Inter, sans-serif';
        ctx.textAlign = 'left';
        ctx.fillText('Medium 1 (n₁ = ' + n1.toFixed(2) + ')', 20, centerY - 20);
        ctx.fillText('Medium 2 (n₂ = ' + n2.toFixed(2) + ')', 20, centerY + 30);

        // Arrow heads for rays
        const drawArrow = (x1, y1, x2, y2, color) => {
            const angle = Math.atan2(y2 - y1, x2 - x1);
            ctx.fillStyle = color;
            ctx.save();
            ctx.translate(x2, y2);
            ctx.rotate(angle);
            ctx.beginPath();
            ctx.moveTo(0, 0);
            ctx.lineTo(-10, -5);
            ctx.lineTo(-10, 5);
            ctx.fill();
            ctx.restore();
        };

        drawArrow(incidentX, incidentY, (incidentX + centerX) / 2, (incidentY + centerY) / 2, '#f59e0b');
        if (!isTIR) {
            const refractX = centerX + rayLength * Math.sin(thetaR);
            const refractY = centerY + rayLength * Math.cos(thetaR);
            drawArrow(centerX, centerY, (centerX + refractX) / 2, (centerY + refractY) / 2, '#3b82f6');
        }
    }
}
